var mapping = {palette: {cyberpunk: ["psychologique", "sombre", "dynamique"],vintage: ["amour", "soleil", "emotion"],dark: ["sombre", "drame", "introspection"],dreamy: ["imaginaire", "melancolie", "emotion"],energetic: ["dynamique", "aventure", "soleil"],},ambiance: {nostalgic: ["melancolie", "emotion", "introspection"],rebellious: ["dynamique", "sombre", "psychologique"],dreamy: ["imaginaire", "amour", "emotion"],mysterious: ["psychologique", "introspection", "sombre"],energetic: ["dynamique", "aventure", "soleil"],},persona: {dreamy: ["imaginaire", "emotion", "melancolie"],epic: ["dynamique", "aventure", "drame"],dark: ["sombre", "psychologique", "introspection"],rebellious: ["dynamique", "sombre", "drame"],surreal: ["imaginaire", "psychologique", "nature"],peaceful: ["nature", "introspection", "emotion"],energetic: ["dynamique", "soleil", "aventure"],},soundtrack: {cyberpunk: ["psychologique", "dynamique", "sombre"],vintage: ["emotion", "amour", "soleil"],dreamy: ["melancolie", "imaginaire", "introspection"],rebellious: ["dynamique", "sombre", "drame"],epic: ["drame", "aventure", "dynamique"],dark: ["introspection", "sombre", "psychologique"],},emotion: {epic: ["dynamique", "aventure", "drame"],nostalgic: ["melancolie", "emotion", "amour"],mysterious: ["psychologique", "sombre", "introspection"],peaceful: ["nature", "introspection", "emotion"],energetic: ["dynamique", "soleil", "aventure"],dark: ["sombre", "drame", "introspection"],},world: {minimalist: ["introspection", "nature", "emotion"],surreal: ["imaginaire", "psychologique", "melancolie"],detailed: ["drame", "emotion", "psychologique"],urban: ["drame", "psychologique", "dynamique"],vintage: ["amour", "emotion", "soleil"],futuristic: ["imaginaire", "dynamique", "aventure"],},};function runMappingSanityCheck() {const issues = [];quizData.forEach((question) => {const mappedQuestion = mapping[question.id];if (!mappedQuestion) {issues.push(`Question sans mapping: "${question.id}"`);return;}question.options.forEach((option) => {const tags = mappedQuestion[option.value];if (!Array.isArray(tags) || tags.length === 0) {issues.push(`Option non mappée: "${question.id}.${option.value}" (label: "${option.label}")`);}});Object.keys(mappedQuestion).forEach((mappedValue) => {const existsInQuiz = question.options.some((opt) => opt.value === mappedValue);if (!existsInQuiz) {issues.push(`Clé mapping orpheline: "${question.id}.${mappedValue}"`);}});});if (issues.length > 0) {console.warn("[Mapping sanity check] Problèmes détectés:");issues.forEach((issue) => console.warn(`- ${issue}`));} else {console.info("[Mapping sanity check] OK");}}
